// HasMealEntitlements applies the HasEdge predicate on the "meal_entitlements" edge.
func HasMealEntitlements() predicate.EventBooking {
	return predicate.EventBooking(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, MealEntitlementsTable, MealEntitlementsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasMealEntitlementsWith applies the HasEdge predicate on the "meal_entitlements" edge with a given conditions (other predicates).
func HasMealEntitlementsWith(preds ...predicate.MealEntitlement) predicate.EventBooking {
	return predicate.EventBooking(func(s *sql.Selector) {
		step := newMealEntitlementsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

